// === Theme preview blob CSS ===
const PREVIEW_BASE_CSS = `
*,*::before,*::after{box-sizing:border-box}
html,body{margin:0;padding:0;background:var(--bg);color:var(--text-1);font-family:var(--font-sans);font-weight:400;line-height:1.5;-webkit-font-smoothing:antialiased;letter-spacing:var(--letter-normal);overflow:hidden;width:100%;height:100%}
.kicker{font-size:11px;font-weight:600;color:var(--accent);letter-spacing:.08em;text-transform:uppercase;margin-bottom:4px}
h2.title{font-family:var(--font-display);font-size:24px;line-height:1.1;font-weight:700;letter-spacing:var(--letter-tight);margin:0 0 6px;color:var(--text-1)}
.title-sm{font-family:var(--font-display);font-size:16px;line-height:1.15;font-weight:700;letter-spacing:var(--letter-tight);margin:0 0 4px;color:var(--text-1)}
.lede{font-size:12px;line-height:1.5;color:var(--text-2);font-weight:400}
.dim{color:var(--text-2);font-size:11px}
.card{background:var(--surface);border:1px solid var(--border);border-radius:var(--radius);padding:10px 14px;box-shadow:var(--shadow)}
.pill{display:inline-block;padding:2px 8px;border-radius:999px;font-size:10px;font-weight:500;background:var(--surface-2);color:var(--text-2);border:1px solid var(--border)}
.pill-accent{background:color-mix(in srgb,var(--accent) 12%,transparent);color:var(--accent);border-color:color-mix(in srgb,var(--accent) 28%,transparent)}
.row{display:flex;gap:8px;align-items:center;flex-wrap:wrap}
.divider-accent{height:2px;width:32px;background:var(--accent);border-radius:1px;margin:6px 0}
`;

function createThemePreviewBlob(theme) {
  const rootVars = [
    `--bg:${theme.bg};--bg-soft:${theme.bgSoft};--surface:${theme.surface};--surface-2:${theme.surface2};`,
    `--border:${theme.border};--border-strong:${theme.borderStrong};`,
    `--text-1:${theme.text1};--text-2:${theme.text2};--text-3:${theme.text3};`,
    `--accent:${theme.accent};--accent-2:${theme.accent2};--accent-3:${theme.accent3};`,
    `--good:${theme.good};--warn:${theme.warn};--bad:${theme.bad};`,
    `--grad:${theme.grad};--grad-soft:${theme.gradSoft};`,
    `--radius:${theme.radius};--radius-sm:${theme.radiusSm};--radius-lg:${theme.radiusLg};`,
    `--shadow:${theme.shadow};--shadow-lg:${theme.shadowLg};`,
    `--font-sans:${theme.fontSans};--font-display:${theme.fontDisplay||theme.fontSans};`,
    `--letter-tight:${theme.letterTight||'-.03em'};--letter-normal:-.01em;--ease:cubic-bezier(.4,0,.2,1);`,
  ].join('');
  const dn = theme.name.split('-').map(w=>w.charAt(0).toUpperCase()+w.slice(1)).join(' ');
  const html = `<!DOCTYPE html><html><head><meta charset="utf-8"><style>@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800;900&family=Noto+Sans+SC:wght@400;500;600;700;900&family=JetBrains+Mono:wght@400;500;700&family=Playfair+Display:ital,wght@0,700;0,900;1,700&family=Space+Grotesk:wght@400;500;600;700&display=swap');:root{${rootVars}}${PREVIEW_BASE_CSS}.preview-wrap{padding:16px 20px;width:100%;height:100%;display:flex;flex-direction:column;justify-content:center}</style></head><body><div class="preview-wrap"><div class="kicker">${theme.category||'THEME PREVIEW'}</div><h2 class="title">${dn}</h2><div class="divider-accent"></div><div class="card" style="margin-top:6px"><div class="title-sm">Card Preview</div><div class="dim">Theme token rendering</div></div><div class="row" style="margin-top:6px"><span class="pill">Default</span><span class="pill-accent">Accent</span></div></div></body></html>`;
  return URL.createObjectURL(new Blob([html], {type:'text/html'}));
}

