// === Helpers ===
function tagBadge(t){const m={light:'☀️浅色',dark:'🌙暗色',bold:'💥大胆',warm:'🔥温暖',effect:'✨特效'},c={light:'tag-light',dark:'tag-dark',bold:'tag-bold',warm:'tag-light',effect:'tag-effect'};return `<span class="theme-tag ${c[t]||'tag-light'}">${m[t]||t}</span>`}

// === Render ===
function renderThemes(){
  const g=document.getElementById('theme-grid'),cats=['Light & Calm','Bold & Statement','Cool & Dark','Warm & Vibrant','Effect-Heavy','Light & Professional','Bold & Editorial','Effect-Heavy / Dramatic'];
  let h='';
  for(const c of cats){const ts=THEMES.filter(t=>t.category===c);if(!ts.length)continue;h+=`<div class="layout-cat-title">${c}</div>`;for(const t of ts){const b=createThemePreviewBlob(t);h+=`<div class="theme-card"><iframe class="theme-card-preview" src="${b}" loading="lazy" title="${t.name}"></iframe><div class="theme-card-info"><div class="theme-card-name">${t.name}</div><div class="theme-card-desc">${t.desc}·${t.use}</div><div class="theme-card-meta">${t.tags.map(tagBadge).join('')}</div></div></div>`}}
  g.innerHTML=h;
}

function renderLayouts(){
  const g=document.getElementById('layout-grid');let h='';
  for(const grp of LAYOUTS){h+=`<div class="layout-cat-title">${grp.cat}</div>`;for(const it of grp.items){h+=`<div class="layout-card"><div class="layout-iframe-wrap"><iframe src="templates/single-page/${it.file}" loading="lazy" title="${it.name}"></iframe></div><div class="layout-card-info"><div class="layout-card-name">${it.file}</div><div class="layout-card-desc"><strong>${it.name}</strong> — ${it.desc}</div></div></div>`}}
  g.innerHTML=h;
}

function renderAnims(){
  document.getElementById('anim-grid-css').innerHTML=CSS_ANIMS.map(([n,e,u])=>`<div class="anim-card" data-anim="${n}" onclick="playAnimOnStage('${n}')"><div class="anim-card-name">.anim-${n}</div><div class="anim-card-desc">${e}</div><div class="anim-card-use">🎯${u}</div></div>`).join('');
  document.getElementById('anim-grid-fx').innerHTML=CANVAS_FX.map(([n,e,u])=>`<div class="anim-fx-card"><iframe class="anim-fx-preview" src="docs/showcase/fx-preview.html?fx=${n}" loading="lazy" title="${n}"></iframe><div class="anim-fx-info"><div class="anim-fx-name">data-fx="${n}"</div><div class="anim-fx-desc">${e}</div><div class="anim-fx-use">🎯${u}</div></div></div>`).join('');
}

function renderTemplates(){
  const g=document.getElementById('tpl-grid'),tc={extracted:'tpl-tag-extracted',scaffold:'tpl-tag-scaffold',presenter:'tpl-tag-presenter'},tl={extracted:'📄真实提取',scaffold:'🔧场景模板',presenter:'🎤演讲者'};
  g.innerHTML=TEMPLATES.map(t=>`<div class="tpl-card"><div class="tpl-iframe-wrap"><iframe src="templates/full-decks/${t.name}/index.html" loading="lazy" title="${t.name}"></iframe></div><div class="tpl-card-info"><div class="tpl-card-name">${String(t.num).padStart(2,'0')}. ${t.name}</div><div class="tpl-card-desc"><strong>${t.subtitle}</strong> — ${t.desc}</div><div class="tpl-card-tags"><span class="tpl-tag ${tc[t.type]}">${tl[t.type]}</span><span class="tpl-tag" style="background:#f0f2f5;color:#888">${t.use}</span></div></div></div>`).join('');
}

// === Animation Stage ===
function playAnimOnStage(name){
  var s=document.getElementById('anim-stage-target');if(!s)return;
  document.querySelectorAll('.anim-card').forEach(function(c){c.classList.remove('active')});
  var card=document.querySelector('.anim-card[data-anim="'+name+'"]');if(card)card.classList.add('active');
  s.style.animation='none';s.style.opacity='0';void s.offsetWidth;
  var label=name.replace(/-/g,' ').toUpperCase(),inner='',animCSS='',dur=2000,isInf=false;
  switch(name){
    case'fade-up':inner='<div style="font-size:36px;font-weight:800;line-height:1.4">Fade Up</div><div style="font-size:14px;opacity:.7;margin-top:4px">从下方+32px淡入</div>';animCSS='kf-fade-up .7s ease both';break;
    case'fade-down':inner='<div style="font-size:36px;font-weight:800;line-height:1.4">Fade Down</div><div style="font-size:14px;opacity:.7;margin-top:4px">从上方-32px淡入</div>';animCSS='kf-fade-down .7s ease both';break;
    case'fade-left':inner='<div style="font-size:36px;font-weight:800;line-height:1.4">Fade Left</div><div style="font-size:14px;opacity:.7;margin-top:4px">从左侧-40px淡入</div>';animCSS='kf-fade-left .7s ease both';break;
    case'fade-right':inner='<div style="font-size:36px;font-weight:800;line-height:1.4">Fade Right</div><div style="font-size:14px;opacity:.7;margin-top:4px">从右侧+40px淡入</div>';animCSS='kf-fade-right .7s ease both';break;
    case'rise-in':inner='<div style="font-size:36px;font-weight:800;line-height:1.4">Rise In</div><div style="font-size:14px;opacity:.7;margin-top:4px">+60px上升+模糊清除</div>';animCSS='kf-rise-in .9s ease both';break;
    case'drop-in':inner='<div style="font-size:36px;font-weight:800;line-height:1.4">Drop In</div><div style="font-size:14px;opacity:.7;margin-top:4px">-60px下落+微缩放</div>';animCSS='kf-drop-in .8s ease both';break;
    case'zoom-pop':inner='<div style="font-size:42px;font-weight:900;line-height:1.2">ZOOM POP</div><div style="font-size:14px;opacity:.7;margin-top:4px">缩放0.6→1.04→1</div>';animCSS='kf-zoom-pop .7s cubic-bezier(.22,1.3,.36,1) both';break;
    case'blur-in':inner='<div style="font-size:36px;font-weight:800;line-height:1.4">Blur In</div><div style="font-size:14px;opacity:.7;margin-top:4px">18px模糊逐渐清晰</div>';animCSS='kf-blur-in .8s ease both';break;
    case'glitch-in':inner='<div style="font-size:40px;font-weight:900;line-height:1.2">GLITCH</div><div style="font-size:14px;opacity:.7;margin-top:4px">Clip-path步进+抖动</div>';animCSS='kf-glitch-stage .8s steps(5,end) both';break;
    case'typewriter':inner='<span class="tw-text" style="font-size:28px;font-weight:900;font-family:\'JetBrains Mono\',monospace;display:inline-block;overflow:hidden;white-space:nowrap;border-right:2px solid currentColor;max-width:100%">> Hello, World!_</span>';animCSS='';break;
    case'neon-glow':inner='<div class="neon-target" style="font-size:36px;font-weight:900;line-height:1.2">NEON GLOW</div><div style="font-size:14px;opacity:.7;margin-top:4px">文字发光脉冲</div>';animCSS='';isInf=true;break;
    case'shimmer-sweep':inner='<div class="shimmer-target" style="font-size:32px;font-weight:800;display:inline-block;overflow:hidden;background:linear-gradient(110deg,#c0caf5 40%,#fff 50%,#c0caf5 60%);background-size:200% 100%;-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text">Shimmer Sweep</div><div style="font-size:14px;opacity:.7;margin-top:4px">白色光泽扫过文字</div>';animCSS='';isInf=true;break;
    case'gradient-flow':inner='<div class="grad-target" style="font-size:30px;font-weight:900;background:linear-gradient(90deg,#ff4d8b,#7a5cff,#36b6ff,#ff4d8b);background-size:300% 100%;-webkit-background-clip:text;-webkit-text-fill-color:transparent">Gradient Flow</div><div style="font-size:14px;opacity:.7;margin-top:4px">背景渐变无限滑动</div>';animCSS='';isInf=true;break;
    case'stagger-list':inner='<div style="font-size:20px;font-weight:700">Item 1</div><div style="font-size:20px;font-weight:700">Item 2</div><div style="font-size:20px;font-weight:700">Item 3</div><div style="font-size:20px;font-weight:700">Item 4</div><div style="font-size:14px;opacity:.5;margin-top:4px">子元素逐行入场</div>';animCSS='';break;
    case'counter-up':inner='<div class="cu-num" style="font-size:60px;font-weight:900;font-variant-numeric:tabular-nums;line-height:1">0</div><div style="font-size:14px;opacity:.7;margin-top:4px">数字0→目标值跳动</div>';animCSS='';break;
    case'path-draw':inner='<svg viewBox="0 0 280 120" style="width:260px;height:110px"><rect x="10" y="10" width="260" height="100" rx="12" fill="none" stroke="#7a5cff" stroke-width="3" stroke-dasharray="800" stroke-dashoffset="800"/><circle cx="140" cy="60" r="30" fill="none" stroke="#ff4d8b" stroke-width="3" stroke-dasharray="200" stroke-dashoffset="200"/></svg><div style="font-size:14px;opacity:.7;margin-top:4px">SVG笔触自绘</div>';animCSS='';break;
    case'morph-shape':inner='<svg viewBox="0 0 200 120" style="width:200px;height:120px"><path fill="none" stroke="#5ef2c6" stroke-width="3" d="M40,60 Q100,10 160,60 Q100,110 40,60 Z"><animate attributeName="d" dur="3s" repeatCount="indefinite" values="M40,60 Q100,10 160,60 Q100,110 40,60 Z;M40,60 Q100,30 160,60 Q100,90 40,60 Z;M40,60 Q100,10 160,60 Q100,110 40,60 Z"/></path></svg><div style="font-size:14px;opacity:.7;margin-top:4px">SVG路径形变</div>';animCSS='';isInf=true;break;
    case'parallax-tilt':inner='<div class="tilt-card" style="width:180px;height:120px;background:linear-gradient(135deg,#7a5cff,#ff4d8b);border-radius:14px;display:flex;align-items:center;justify-content:center;font-size:20px;font-weight:700;color:#fff;transform-style:preserve-3d;transition:transform .4s ease">Hover Me</div><div style="font-size:14px;opacity:.7;margin-top:4px">鼠标悬停→3D倾斜</div>';animCSS='';break;
    case'card-flip-3d':inner='<div style="width:160px;height:100px;background:linear-gradient(135deg,#7a5cff,#3b82f6);border-radius:12px;display:flex;align-items:center;justify-content:center;font-size:18px;font-weight:700;color:#fff;margin:0 auto">FLIP</div><div style="font-size:14px;opacity:.7;margin-top:4px">Y轴90°翻转</div>';animCSS='kf-card-flip-3d .8s ease both';break;
    case'cube-rotate-3d':inner='<div style="width:100px;height:100px;background:linear-gradient(135deg,#7a5cff,#ff4d8b);border-radius:12px;display:flex;align-items:center;justify-content:center;font-size:18px;font-weight:700;color:#fff;margin:0 auto">CUBE</div><div style="font-size:14px;opacity:.7;margin-top:4px">立方体面旋入</div>';animCSS='kf-cube-rotate-3d .8s ease both';break;
    case'page-turn-3d':inner='<div style="width:180px;height:110px;background:linear-gradient(135deg,#f0f2f5,#e0e3ea);border-radius:4px 12px 12px 4px;display:flex;align-items:center;justify-content:center;font-size:18px;font-weight:700;color:#333;border-left:4px solid #ccc;margin:0 auto">PAGE</div><div style="font-size:14px;opacity:.7;margin-top:4px">左铰链翻页</div>';animCSS='kf-page-turn-3d .9s ease both';break;
    case'perspective-zoom':inner='<div style="font-size:34px;font-weight:900;line-height:1.2">ZOOM IN</div><div style="font-size:14px;opacity:.7;margin-top:4px">从-400 Z拉近</div>';animCSS='kf-perspective-zoom .9s ease both';break;
    case'marquee-scroll':inner='<div style="overflow:hidden;width:100%"><div style="display:flex;gap:40px;white-space:nowrap;font-size:24px;font-weight:700;color:#7a5cff">Logo A · Logo B · Logo C · Logo D · Logo E · Logo A · Logo B · Logo C · Logo D · Logo E</div></div><div style="font-size:14px;opacity:.7;margin-top:4px">无限水平循环滚动</div>';animCSS='';break;
    case'kenburns':inner='<div style="font-size:30px;font-weight:800;line-height:1.2">Ken Burns</div><div style="font-size:14px;opacity:.7;margin-top:4px">14s慢速缩放（背景）</div>';animCSS='kf-kenburns 6s ease both';break;
    case'confetti-burst':inner='<div style="font-size:36px;font-weight:900;line-height:1.2">🎉 CONFETTI 🎉</div><div style="font-size:14px;opacity:.7;margin-top:4px">五彩纸屑爆发</div>';animCSS='kf-confetti-burst .8s ease both';break;
    case'spotlight':inner='<div style="font-size:32px;font-weight:800;line-height:1.2;color:#5ef2c6">SPOTLIGHT</div><div style="font-size:14px;opacity:.7;margin-top:4px">圆形裁剪揭示</div>';animCSS='kf-spotlight 1s ease both';break;
    case'ripple-reveal':inner='<div style="font-size:32px;font-weight:800;line-height:1.2;color:#ff6ec7">RIPPLE REVEAL</div><div style="font-size:14px;opacity:.7;margin-top:4px">角落波纹扩散</div>';animCSS='kf-ripple-reveal 1s ease both';break;
    default:inner='<div style="font-size:36px;font-weight:800;line-height:1.4">'+label+'</div>';animCSS='kf-fade-up .7s ease both';
  }
  s.innerHTML=inner;s.style.opacity='1';
  if(animCSS)s.style.animation=animCSS;
  if(name==='shimmer-sweep'){var st=s.querySelector('.shimmer-target');if(st)st.style.animation='kf-shimmer-sweep 2.4s ease infinite'}
  if(name==='neon-glow'){var nt=s.querySelector('.neon-target');if(nt)nt.style.animation='kf-neon-pulse 2s ease-in-out infinite'}
  if(name==='gradient-flow'){var gt=s.querySelector('.grad-target');if(gt)gt.style.animation='kf-grad-flow 4s linear infinite'}
  if(name==='typewriter'){var tw=s.querySelector('.tw-text');if(tw){tw.style.width='0';void tw.offsetWidth;tw.style.animation='kf-typewriter 2.4s steps(20,end) forwards, kf-caret-blink 1s step-end infinite'}}
  if(name==='stagger-list'){var items=s.querySelectorAll('div');items.forEach(function(item,i){if(i<4){item.style.opacity='0';item.style.animation='kf-rise-in .5s ease both';item.style.animationDelay=(i*.12)+'s'}})}
  if(name==='counter-up'){var ne=s.querySelector('.cu-num');if(ne){var tgt=1248,st=0,steps=30,sti=40,inc=tgt/steps,count=st;var tm=setInterval(function(){count+=inc;if(count>=tgt){count=tgt;clearInterval(tm)}ne.textContent=Math.floor(count).toLocaleString()},sti);s._counterTimer=tm}}
  if(name==='path-draw'){var ps=s.querySelectorAll('rect,circle');ps.forEach(function(p,i){p.style.animation='kf-path-draw 1.5s ease forwards';p.style.animationDelay=(i*.3)+'s'})}
  if(name==='marquee-scroll'){var wr=s.querySelector('div>div');if(wr)wr.style.animation='kf-marquee-scroll 8s linear infinite'}
  if(name==='parallax-tilt'){var tc=s.querySelector('.tilt-card');if(tc){tc.addEventListener('mousemove',function(e){var r=tc.getBoundingClientRect(),x=(e.clientX-r.left)/r.width-.5,y=(e.clientY-r.top)/r.height-.5;tc.style.transform='perspective(600px) rotateY('+(x*20)+'deg) rotateX('+(-y*20)+'deg) translateZ(10px)'});tc.addEventListener('mouseleave',function(){tc.style.transform='perspective(600px) rotateY(0) rotateX(0) translateZ(0)'})}}
  clearTimeout(s._resetTimer);
  s._resetTimer=setTimeout(function(){s.style.animation='none';if(!isInf){s.style.opacity='1';s.innerHTML='<div style="font-size:28px;font-weight:800">'+label+'</div><div style="font-size:13px;opacity:.6;margin-top:4px">动画已播放 ✓</div>'}if(s._counterTimer){clearInterval(s._counterTimer);s._counterTimer=null}},isInf?6000:dur);
}

// === Copy ===
function copyInstall(){var cmd=document.getElementById('install-cmd').textContent,btn=document.querySelector('.btn-copy');if(navigator.clipboard){navigator.clipboard.writeText(cmd).then(function(){btn.classList.add('copied');btn.querySelector('.copy-text').textContent='已复制 ✓';setTimeout(function(){btn.classList.remove('copied');btn.querySelector('.copy-text').textContent='复制'},2000)})}else{var ta=document.createElement('textarea');ta.value=cmd;ta.style.position='fixed';ta.style.opacity='0';document.body.appendChild(ta);ta.select();document.execCommand('copy');document.body.removeChild(ta);btn.querySelector('.copy-text').textContent='已复制 ✓';setTimeout(function(){btn.querySelector('.copy-text').textContent='复制'},2000)}}
window.copyInstall=copyInstall;

// === Sidebar ===
function updateSidebar(){var secs=document.querySelectorAll('section[id], .hero[id]'),links=document.querySelectorAll('.sidebar-nav a'),cur='';secs.forEach(function(s){if(s.getBoundingClientRect().top<200)cur=s.id});links.forEach(function(a){a.classList.toggle('active',a.getAttribute('href')==='#'+cur)})}

// === Init ===
document.addEventListener('DOMContentLoaded',function(){renderThemes();renderLayouts();renderAnims();renderTemplates();window.addEventListener('scroll',updateSidebar);updateSidebar()});

